import{_ as s,o as a,c as n,a2 as t}from"./chunks/framework.CKCxdkvf.js";const u=JSON.parse('{"title":"IA — Information Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"uxs/IA.md","filePath":"uxs/IA.md"}'),o={name:"uxs/IA.md"};function r(i,e,p,l,c,d){return a(),n("div",null,[...e[0]||(e[0]=[t(`<h1 id="ia-—-information-architecture" tabindex="-1">IA — Information Architecture <a class="header-anchor" href="#ia-—-information-architecture" aria-label="Permalink to &quot;IA — Information Architecture&quot;">​</a></h1><p><em>Orrery · Reference document · v1.1 · April 2026</em></p><p>This is the reference document for the UX plane. UXSes anchor to it by section. When surfaces, navigation, tokens, or shell regions change, this document is amended.</p><hr><h2 id="§overview" tabindex="-1">§overview <a class="header-anchor" href="#§overview" aria-label="Permalink to &quot;§overview&quot;">​</a></h2><p>Six screens, one persistent nav bar, SvelteKit&#39;s History API router. No login state. No user data. No persistence between sessions.</p><p>The narrative arc: Moon Map (prologue) → Solar System Explorer (Act 1) → Mission Configurator (Act 2) → Mission Arc (Act 3) → Mission Library (archive) → Earth Orbit (context). The nav bar presents all six destinations at all times. There is no enforced sequence.</p><hr><h2 id="§surfaces" tabindex="-1">§surfaces <a class="header-anchor" href="#§surfaces" aria-label="Permalink to &quot;§surfaces&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Surface</th><th>Route</th><th>File</th><th>Primary canvas</th></tr></thead><tbody><tr><td>Moon Map</td><td><code>/moon</code></td><td><code>src/routes/moon/+page.svelte</code></td><td>Three.js sphere + Canvas 2D flat map</td></tr><tr><td>Solar System Explorer</td><td><code>/explore</code></td><td><code>src/routes/explore/+page.svelte</code></td><td>Three.js 3D + Canvas 2D toggle</td></tr><tr><td>Mission Configurator</td><td><code>/plan</code></td><td><code>src/routes/plan/+page.svelte</code></td><td>Canvas 2D porkchop plot</td></tr><tr><td>Mission Arc</td><td><code>/fly</code></td><td><code>src/routes/fly/+page.svelte</code></td><td>Three.js 3D + Canvas 2D toggle</td></tr><tr><td>Mission Library</td><td><code>/missions</code></td><td><code>src/routes/missions/+page.svelte</code></td><td>CSS grid card layout</td></tr><tr><td>Earth Orbit</td><td><code>/earth</code></td><td><code>src/routes/earth/+page.svelte</code></td><td>Canvas 2D logarithmic scale</td></tr></tbody></table><hr><h2 id="§topbar-patterns" tabindex="-1">§topbar-patterns <a class="header-anchor" href="#§topbar-patterns" aria-label="Permalink to &quot;§topbar-patterns&quot;">​</a></h2><p>One topbar pattern: the persistent 52px nav bar.</p><p><strong>Persistent nav bar</strong> — present on all six screens without exception.</p><ul><li>Height: <code>52px</code></li><li>Background: <code>rgba(4,4,12,0.92)</code></li><li>Border-bottom: <code>1px solid rgba(255,255,255,0.07)</code></li><li>Backdrop-filter: <code>blur(14px)</code></li><li>Z-index: <code>20</code></li></ul><p>Left region: ORRERY wordmark (Bebas Neue 26px, letter-spacing 4px) + &quot;MISSION SIMULATOR&quot; subtitle (Space Mono 8px, rgba(255,255,255,0.22)).</p><p>Centre region: six screen links. Active screen: white text, <code>rgba(68,102,255,0.28)</code> background, <code>rgba(68,102,255,0.55)</code> border. Inactive: <code>rgba(255,255,255,0.28)</code>, transparent border, hover to <code>rgba(255,255,255,0.85)</code>.</p><p>Right region: screen-specific controls (3D/2D toggle on explore and fly, CAPCOM toggle on fly, status indicator on fly).</p><hr><h2 id="§navigation" tabindex="-1">§navigation <a class="header-anchor" href="#§navigation" aria-label="Permalink to &quot;§navigation&quot;">​</a></h2><p>History API routing via SvelteKit&#39;s built-in router. Format: <code>/[screen]</code> with optional query params for mission IDs.</p><table tabindex="0"><thead><tr><th>Pattern</th><th>Example</th><th>Used by</th></tr></thead><tbody><tr><td><code>/[screen]</code></td><td><code>/explore</code></td><td>All screens</td></tr><tr><td><code>/fly?mission=[id]</code></td><td><code>/fly?mission=curiosity</code></td><td>Mission Arc (loads specific mission)</td></tr><tr><td><code>/missions?dest=[MARS|MOON]</code></td><td><code>/missions?dest=MARS</code></td><td>Mission Library (pre-filtered)</td></tr></tbody></table><p>Navigation triggers: nav bar links, &quot;PLAN A MISSION&quot; button in explore screen, &quot;FLY THIS MISSION&quot; button in missions screen.</p><p>History API routing is locked in ADR-013 (superseding ADR-004). RFC-001 is closed — SvelteKit&#39;s router replaces the hand-written router originally proposed.</p><hr><h2 id="§url-structure" tabindex="-1">§url-structure <a class="header-anchor" href="#§url-structure" aria-label="Permalink to &quot;§url-structure&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/explore                                       Solar System Explorer</span></span>
<span class="line"><span>/plan                                          Mission Configurator (Mars default)</span></span>
<span class="line"><span>/plan?dest=jupiter&amp;type=flyby                  Multi-destination (ADR-026): dest=mercury|venus|mars|jupiter|saturn; type=landing|flyby</span></span>
<span class="line"><span>/fly                                           Mission Arc (default scenario: ORRERY DEMO free-return)</span></span>
<span class="line"><span>/fly?mission=id                                Mission Arc (specific mission from library)</span></span>
<span class="line"><span>/fly?dest=jupiter&amp;type=flyby&amp;dep=N&amp;tof=N       Mission Arc (synthesised from /plan selection, ADR-026)</span></span>
<span class="line"><span>/missions                                      Mission Library (all missions)</span></span>
<span class="line"><span>/missions?dest=MARS&amp;status=ACTIVE&amp;agency=NASA  Mission Library filtered (ADR-024)</span></span>
<span class="line"><span>/earth                                         Earth Orbit</span></span>
<span class="line"><span>/moon                                          Moon Map</span></span></code></pre></div><p>Routes resolve client-side via SvelteKit&#39;s router. Servers must serve <code>index.html</code> for unmatched paths (<code>try_files $uri /index.html</code> in nginx, <code>404.html</code> SPA-redirect on GitHub Pages — see ADR-014).</p><hr><h2 id="§shell-regions" tabindex="-1">§shell-regions <a class="header-anchor" href="#§shell-regions" aria-label="Permalink to &quot;§shell-regions&quot;">​</a></h2><p>Regions that persist across or within a screen.</p><p><strong>Nav bar</strong> — <code>height: 52px</code>, <code>top: 0</code>, <code>left: 0</code>, <code>right: 0</code>. Present on all screens. Z-index 20. Contains wordmark, screen links, screen-specific controls.</p><p><strong>Right detail panel</strong> — <code>width: 314px</code>, <code>top: 52px</code>, <code>right: 0</code>, <code>bottom: 68px</code> (68px on fly screen) or <code>bottom: 0</code>. Slides in on click. Present on: explore (planet/body panels), missions (mission detail), moon (site panels). Absent on: plan, fly, earth (these have dedicated HUD layouts).</p><p><strong>Bottom bar</strong> — <code>height: 68px</code>, <code>bottom: 0</code>, <code>left: 0</code>, <code>right: 0</code>. Present on: fly (timeline scrubber, play/pause, speed controls). Absent on all other screens.</p><p><strong>HUD panels</strong> — fly screen has four fixed-position panels (left identity, right navigation, right systems, CAPCOM panels). These are screen-specific, not shared shell regions.</p><hr><h2 id="§shared-tokens" tabindex="-1">§shared-tokens <a class="header-anchor" href="#§shared-tokens" aria-label="Permalink to &quot;§shared-tokens&quot;">​</a></h2><p>Tokens that apply across all surfaces. UXSes inherit these by name and do not redefine them locally.</p><h3 id="colour-tokens" tabindex="-1">Colour tokens <a class="header-anchor" href="#colour-tokens" aria-label="Permalink to &quot;Colour tokens&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>color-bg:         #04040c    Background — near-black with blue undertone</span></span>
<span class="line"><span>color-accent:     #4466ff    Primary accent — blue</span></span>
<span class="line"><span>color-teal:       #4ecdc4    Secondary accent — teal (CAPCOM, active states)</span></span>
<span class="line"><span>color-mars:       #c1440e    Mars red — danger, Mars-specific</span></span>
<span class="line"><span>color-earth:      #4b9cd3    Earth blue — information, Earth-specific</span></span>
<span class="line"><span>color-gold:       #ffc850    Gold — Sun, perihelion, caution</span></span>
<span class="line"><span>color-text:       #ffffff    Primary text</span></span>
<span class="line"><span>color-text-dim:   rgba(255,255,255,0.35)   Dimmed text</span></span>
<span class="line"><span>color-text-faint: rgba(255,255,255,0.15)   Very faint text / labels</span></span>
<span class="line"><span>color-border:     rgba(255,255,255,0.07)   Standard border</span></span>
<span class="line"><span>color-panel-bg:   rgba(4,4,12,0.97)        Panel background</span></span>
<span class="line"><span>color-hud-bg:     rgba(5,5,20,0.88)        HUD panel background</span></span></code></pre></div><h3 id="link-tier-colours" tabindex="-1">Link tier colours <a class="header-anchor" href="#link-tier-colours" aria-label="Permalink to &quot;Link tier colours&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>color-tier-intro: #4ecdc4    Introductory links (Wikipedia, agency pages)</span></span>
<span class="line"><span>color-tier-core:  #7b9cff    Core links (MIT OCW, technical overviews)</span></span>
<span class="line"><span>color-tier-deep:  #ff9966    Deep links (peer-reviewed papers)</span></span></code></pre></div><h3 id="typography-tokens" tabindex="-1">Typography tokens <a class="header-anchor" href="#typography-tokens" aria-label="Permalink to &quot;Typography tokens&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>font-display:   &#39;Bebas Neue&#39;, sans-serif    Titles, screen names, mission names</span></span>
<span class="line"><span>font-mono:      &#39;Space Mono&#39;, monospace     All data, labels, HUD values, UI chrome</span></span>
<span class="line"><span>font-editorial: &#39;Crimson Pro&#39;, serif        Editorial descriptions, fact text (always italic)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>size-nav-title:   26px    Nav bar wordmark</span></span>
<span class="line"><span>size-panel-title: 32–42px Panel planet/mission name (varies by name length)</span></span>
<span class="line"><span>size-hud-value:   10–16px HUD telemetry values</span></span>
<span class="line"><span>size-label:       7–8px   UI labels (Space Mono, letter-spacing 2px)</span></span>
<span class="line"><span>size-data:        9–11px  Data values</span></span>
<span class="line"><span>size-editorial:   12–13px Crimson Pro italic body text</span></span></code></pre></div><h3 id="spacing-tokens" tabindex="-1">Spacing tokens <a class="header-anchor" href="#spacing-tokens" aria-label="Permalink to &quot;Spacing tokens&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>nav-height:     52px</span></span>
<span class="line"><span>panel-width:    314px</span></span>
<span class="line"><span>bottom-bar-h:   68px</span></span>
<span class="line"><span>panel-pad:      14px 18px</span></span>
<span class="line"><span>hud-pad:        12px 16px</span></span>
<span class="line"><span>border-radius:  4–6px   Panels and cards</span></span></code></pre></div><h3 id="agency-colours" tabindex="-1">Agency colours <a class="header-anchor" href="#agency-colours" aria-label="Permalink to &quot;Agency colours&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>color-nasa:       #0B3D91</span></span>
<span class="line"><span>color-esa:        #003299</span></span>
<span class="line"><span>color-cnsa:       #DE2910</span></span>
<span class="line"><span>color-isro:       #FF9933</span></span>
<span class="line"><span>color-roscosmos:  #8B0000</span></span>
<span class="line"><span>color-jaxa:       #003087</span></span>
<span class="line"><span>color-spacex:     #005288</span></span></code></pre></div><hr><h2 id="§state-persistence" tabindex="-1">§state-persistence <a class="header-anchor" href="#§state-persistence" aria-label="Permalink to &quot;§state-persistence&quot;">​</a></h2><p>No state is persisted between sessions. <code>localStorage</code> and <code>sessionStorage</code> are not used. All screen state is held in memory and reset on navigation.</p><p>The one exception is URL-encoded state: mission ID and filter params in the URL hash allow a specific view to be bookmarked and shared.</p><hr><h2 id="§entry-points" tabindex="-1">§entry-points <a class="header-anchor" href="#§entry-points" aria-label="Permalink to &quot;§entry-points&quot;">​</a></h2><p>SvelteKit&#39;s standard entry: <code>src/app.html</code> is the document shell; <code>src/routes/+layout.svelte</code> is the root layout that wraps all routes. Deep-linking to any route is supported by the server-side catch-all (<code>try_files $uri /index.html</code> for nginx, <code>404.html</code> SPA-redirect for GitHub Pages per ADR-014).</p><hr><h2 id="§surface-map" tabindex="-1">§surface-map <a class="header-anchor" href="#§surface-map" aria-label="Permalink to &quot;§surface-map&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                 ┌─────────────────────────────────────────┐</span></span>
<span class="line"><span>                 │         Persistent nav bar               │</span></span>
<span class="line"><span>                 │  MOON  EXPLORE  PLAN  FLY  MISSIONS  EARTH │</span></span>
<span class="line"><span>                 └─────────────────────────────────────────┘</span></span>
<span class="line"><span>                          │       │       │</span></span>
<span class="line"><span>              ┌───────────┘       │       └──────────┐</span></span>
<span class="line"><span>              ▼                   ▼                  ▼</span></span>
<span class="line"><span>         Moon Map          Solar System        Mission Library</span></span>
<span class="line"><span>         3D sphere         Explorer            card grid</span></span>
<span class="line"><span>         2D flat map       3D/2D toggle        → fly screen</span></span>
<span class="line"><span>              │                   │</span></span>
<span class="line"><span>              │            Mission Config</span></span>
<span class="line"><span>              │            porkchop plot</span></span>
<span class="line"><span>              │                   │</span></span>
<span class="line"><span>              └────────────►  Mission Arc ◄──────────┘</span></span>
<span class="line"><span>                           3D/2D toggle</span></span>
<span class="line"><span>                           CAPCOM mode</span></span>
<span class="line"><span></span></span>
<span class="line"><span>         Earth Orbit — standalone, no inbound navigation</span></span></code></pre></div><hr><h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Version</th><th>Date</th><th>Change</th></tr></thead><tbody><tr><td>v1.0</td><td>April 2026</td><td>Initial version — surfaces, tokens, shell regions extracted from 05_Design_System.md and six prototypes</td></tr><tr><td>v1.1</td><td>April 2026</td><td>§overview, §surfaces, §navigation, §url-structure, §entry-points updated to reflect History API routing (ADR-013) and SvelteKit routes/components (ADR-012). Hash-routing examples replaced with clean URLs.</td></tr></tbody></table>`,61)])])}const g=s(o,[["render",r]]);export{u as __pageData,g as default};
